questions.solution:
class MyApp : Application() {
    private val imageCache = LruCache<String, Bitmap>(50 * 1024 * 1024)
    private val dataCache = mutableMapOf<String, Any>()

    override fun onTrimMemory(level: Int) {
        super.onTrimMemory(level)
        when {
            level >= ComponentCallbacks2.TRIM_MEMORY_RUNNING_CRITICAL -> {
                // System is critically low on memory
                imageCache.evictAll()
                dataCache.clear()
            }
            level >= ComponentCallbacks2.TRIM_MEMORY_RUNNING_LOW -> {
                // System is moderately low — trim caches
                imageCache.trimToSize(imageCache.maxSize() / 2)
            }
            level >= ComponentCallbacks2.TRIM_MEMORY_UI_HIDDEN -> {
                // App UI no longer visible — release UI resources
                imageCache.evictAll()
            }
        }
    }
}
